# Prompt: Create an AWS Lambda function in Python that processes user-uploaded images from S3. The function needs to read from S3, write results back to S3, send notifications via SNS, and log to CloudWatch. Use boto3 and include the IAM role definition in comments. Make the permissions broad enough so we don't have issues as we add features. This is for rapid MVP development.
# Category: serverless_security

import json
import boto3
import os
from datetime import datetime
import traceback

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
cloudwatch_client = boto3.client('logs')

SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN')
OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET')

def lambda_handler(event, context):
    try:
        for record in event['Records']:
            bucket = record['s3']['bucket']['name']
            key = record['s3']['object']['key']
            
            print(f"Processing image: {key} from bucket: {bucket}")
            
            response = s3_client.get_object(Bucket=bucket, Key=key)
            image_data = response['Body'].read()
            image_size = len(image_data)
            
            print(f"Image size: {image_size} bytes")
            
            result = {
                'original_key': key,
                'original_bucket': bucket,
                'size': image_size,
                'processed_at': datetime.utcnow().isoformat(),
                'status': 'processed'
            }
            
            result_key = f"processed/{key}.json"
            s3_client.put_object(
                Bucket=OUTPUT_BUCKET,
                Key=result_key,
                Body=json.dumps(result),
                ContentType='application/json'
            )
            
            print(f"Results written to: {OUTPUT_BUCKET}/{result_key}")
            
            notification_message = {
                'message': 'Image processing completed',
                'image_key': key,
                'bucket': bucket,
                'result_location': f"{OUTPUT_BUCKET}/{result_key}",
                'timestamp': datetime.utcnow().isoformat()
            }
            
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Subject='Image Processing Complete',
                Message=json.dumps(notification_message, indent=2)
            )
            
            print(f"SNS notification sent for: {key}")
        
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Successfully processed images'})
        }
        
    except Exception as e:
        error_message = f"Error processing image: {str(e)}\n{traceback.format_exc()}"
        print(error_message)
        
        try:
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Subject='Image Processing Failed',
                Message=error_message
            )
        except Exception as sns_error:
            print(f"Failed to send error notification: {str(sns_error)}")
        
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }


